from flask import Flask, request, jsonify
from urllib.parse import urlparse

app = Flask(__name__)

# Registered base URL for redirect URIs
REGISTERED_BASE_URI = "https://example.com/oauth"

@app.route('/authorize', methods=['GET'])
def authorize():
    redirect_uri = request.args.get('redirect_uri')
    
    if not redirect_uri:
        return jsonify({"error": "Missing redirect_uri"}), 400
    
    if not is_valid_redirect_uri(redirect_uri):
        return jsonify({"error": "Invalid redirect_uri"}), 400
    
    # Proceed with authorization logic
    return jsonify({"message": "Authorization successful", "redirect_uri": redirect_uri})

def is_valid_redirect_uri(redirect_uri):
    parsed_uri = urlparse(redirect_uri)
    return parsed_uri.scheme in ['http', 'https'] and redirect_uri.startswith(REGISTERED_BASE_URI)

